/**
 * Sample code: Hello World with PostgreSQL and MongoDB connectivity.
 */

const { getPostgresVersion } = require("./postgres-service");
const { getMongoVersion } = require("./mongo-service");

/**
 * PostgreSQL configuration loaded from environment variables with sensible defaults.
 *
 * @type {Object}
 */
const pgConfig = {
  host: process.env.POSTGRES_HOST || "localhost",
  port: parseInt(process.env.POSTGRES_PORT || "5432"),
  user: process.env.POSTGRES_USER || "test",
  password: process.env.POSTGRES_PASS || "test",
  database: process.env.POSTGRES_NAME || "test",
  connectionTimeout: 15,
};

/**
 * MongoDB configuration loaded from environment variables.
 * Null when MONGO_HOST is not set (e.g. DocumentDB disabled on AWS).
 *
 * @type {Object|null}
 */
const _mongoHost = process.env.MONGO_HOST || "";
const mongoConfig = _mongoHost ? {
  host: _mongoHost,
  port: parseInt(process.env.MONGO_PORT || "27017"),
  user: process.env.MONGO_USER || "",
  password: process.env.MONGO_PASS || "",
  database: process.env.MONGO_NAME || "",
  isLocal: process.env.IS_LOCAL === "true",
  serverSelectionTimeoutMS: 5000,
  socketTimeoutMS: 45000,
} : null;

/**
 * Sample code: Hello World with PostgreSQL and MongoDB connectivity.
 *
 * @param {Object} event - The Lambda event
 * @param {Object} context - The Lambda context
 * @returns {Promise} A response object with statusCode, headers, and body
 */
exports.handler = async (event, context) => {
  console.log("Received event: ", event)
  console.log("Received context: ", context)

  try {
    // Retrieve versions — MongoDB skipped if not configured
    const pgVersion = await getPostgresVersion(pgConfig);
    const mongoVersion = mongoConfig ? await getMongoVersion(mongoConfig) : null;

    // Log retrieved versions for debugging
    console.log("PostgreSQL Version: ", pgVersion);
    console.log("MongoDB Version: ", mongoVersion);

    // Return successful response with database versions
    return {
      statusCode: 200,
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        message: "Hello, World!",
        postgres: pgVersion,
        mongodb: mongoVersion,
      }),
    };
  } catch (error) {
    // Return error response on any exception
    console.error("Handler error:", error);
    return {
      statusCode: 500,
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        error: "Failed to retrieve database versions",
        message: error.message,
      }),
    };
  }
}

/**
 * MongoDB database configuration and connection management.
 *
 * This module handles MongoDB connection pooling using module-level variables
 * to reuse connections across Lambda invocations, improving performance and reducing
 * cold start time.
 */

const { MongoClient } = require("mongodb");

/**
 * Module-level MongoDB client for connection pooling across Lambda invocations.
 * Persists between invocations within the same Lambda container.
 * @type {MongoClient|null}
 */
let mongoClient = null;

/**
 * Retrieves the MongoDB version using connection pooling.
 *
 * Reuses the module-level mongoClient across invocations for better performance.
 * Executes the admin.buildInfo command to retrieve version information.
 * On connection failure or command error, resets the client to null and throws the error.
 *
 * Connection pooling strategy:
 * - First invocation: Creates a new MongoDB client and stores it in mongoClient
 * - Subsequent invocations: Reuses the existing client
 * - On error: Resets mongoClient to null to force reconnection on next invocation
 *
 * @param {*} config MongoDB configuration object with host, port, user, password
 * @returns {Promise} The MongoDB version string, or "unknown" if retrieval fails
 * @throws {Error} If connection or command fails
 */
async function getMongoVersion(config) {
  try {
    // Build MongoDB connection URI — include credentials only when provided
    const auth = config.user ? `${config.user}:${config.password}@` : "";
    const uri = `mongodb://${auth}${config.host}:${config.port}`;

    // Create client if not already pooled
    if (!mongoClient) {
      mongoClient = new MongoClient(uri, {
        serverSelectionTimeoutMS: config.serverSelectionTimeoutMS,
        socketTimeoutMS: config.socketTimeoutMS,
        ...(config.isLocal ? {} : { tls: true, tlsAllowInvalidCertificates: true, retryWrites: false }),
      });
      await mongoClient.connect();
    }

    // Execute buildInfo command and extract version
    const info = await mongoClient.db("admin").command({ buildInfo: 1 });
    return info.version || "unknown";
  } catch (error) {
    // Connection or command failed - reset client and throw error
    console.error("MongoDB error:", error.message);
    mongoClient = null;
    throw error;
  }
}

module.exports = {
  getMongoVersion,
};

"""
AWS Lambda handler for Achievements service.
Provides Catalog and Award management.
"""

import json
import logging
import os
from db import (
    init_table,
    create_catalog_item,
    get_all_catalog_items,
    delete_catalog_item,
    create_award,
    get_all_awards,
    delete_award,
)

logger = logging.getLogger()
logger.setLevel(logging.INFO)

IS_LOCAL = os.getenv("IS_LOCAL", "false") == "true"
PG_CONFIG = (
    f"host={os.getenv('POSTGRES_HOST', 'localhost')} "
    f"port={os.getenv('POSTGRES_PORT', '5432')} "
    f"user={os.getenv('POSTGRES_USER', 'postgres')} "
    f"password={os.getenv('POSTGRES_PASS', 'postgres123')} "
    f"dbname={os.getenv('POSTGRES_NAME', 'postgres')} "
    f"connect_timeout=15"
)
if not IS_LOCAL:
    PG_CONFIG += " sslmode=require"

_initialized = False

def _ensure_init():
    global _initialized
    if not _initialized:
        init_table(PG_CONFIG)
        _initialized = True

def handler(event=None, context=None):
    """Lambda handler routing for catalog and awards."""
    _ensure_init()

    try:
        method = event.get("requestContext", {}).get("http", {}).get("method", "GET")
        path = event.get("rawPath", "")
        query_params = event.get("queryStringParameters") or {}
        body = {}

        if event.get("body"):
            try:
                body = json.loads(event["body"])
            except (json.JSONDecodeError, TypeError):
                return response(400, {"error": "Invalid JSON body"})

        resource_id = extract_id(path)

        if method == "POST":
            if path.endswith("/catalog"):
                return handle_create_catalog(body)
            elif path.endswith("/award"):
                return handle_create_award(body)
            return response(400, {"error": f"Invalid POST path: {path}. Use /catalog or /award."})
        elif method == "GET":
            if path.endswith("/catalog"):
                return handle_get_catalog()
            return handle_get_awards(query_params)
        elif method == "DELETE":
            if not resource_id:
                return response(400, {"error": "ID is required for delete"})
            if "/catalog" in path:
                return handle_delete_catalog(resource_id)
            return handle_delete_award(resource_id)
        else:
            return response(405, {"error": f"Method {method} not allowed"})

    except Exception as e:
        logger.error("Handler error: %s", str(e))
        return response(500, {"error": "Internal server error", "message": str(e)})

def handle_create_catalog(body):
    """Handle POST /api/achievements-service/catalog"""
    if not body.get("title"):
        return response(400, {"error": "title is required for catalog items"})
    item = create_catalog_item(PG_CONFIG, body)
    return response(201, item)

def handle_get_catalog():
    """Handle GET /api/achievements-service/catalog"""
    items = get_all_catalog_items(PG_CONFIG)
    return response(200, items)

def handle_delete_catalog(resource_id):
    """Handle DELETE /api/achievements-service/catalog/{id}"""
    deleted = delete_catalog_item(PG_CONFIG, resource_id)
    if not deleted:
        return response(404, {"error": "Catalog item not found"})
    return response(204, None)

def handle_create_award(body):
    """Handle POST /api/achievements-service/award"""
    if not body.get("catalog_id"):
        return response(400, {"error": "catalog_id is required for awards"})
    if not body.get("awarded_date"):
        return response(400, {"error": "awarded_date is required for awards"})

    award = create_award(PG_CONFIG, body)
    return response(201, award)

def handle_get_awards(params):
    """Handle GET /api/achievements-service/award (or default GET)"""
    team_id = params.get("team_id")
    individual_id = params.get("individual_id")
    awards = get_all_awards(PG_CONFIG, team_id=team_id, individual_id=individual_id)
    return response(200, awards)

def handle_delete_award(resource_id):
    """Handle DELETE /api/achievements-service/award/{id}"""
    deleted = delete_award(PG_CONFIG, resource_id)
    if not deleted:
        return response(404, {"error": "Award not found"})
    return response(204, None)

def extract_id(path):
    """Extract resource ID from URL path."""
    parts = [p for p in path.split("/") if p]
    if len(parts) >= 3 and parts[0] == "api":
        # Supports /api/achievements-service/catalog/{id} or /api/achievements-service/award/{id}
        # or just /api/achievements-service/{id}
        return parts[-1] if len(parts) > 2 else None
    return None

def response(status_code, body):
    """Build a Lambda response object."""
    resp = {
        "statusCode": status_code,
        "headers": {
            "Content-Type": "application/json",
            "Access-Control-Allow-Origin": "*",
            "Access-Control-Allow-Methods": "GET, POST, PUT, DELETE, OPTIONS",
            "Access-Control-Allow-Headers": "Content-Type, Authorization",
        },
    }
    if body is not None:
        resp["body"] = json.dumps(body, default=str)
    return resp

if __name__ == "__main__":
    print(handler({"requestContext": {"http": {"method": "GET"}}, "rawPath": "/api/achievements-service/catalog"}, None))

"""
AWS Lambda handler for Individuals service.
Provides CRUD operations for managing individual team members.
Routes: POST/GET/PUT/DELETE /api/individuals-service
"""

import json
import logging
import os
import urllib.parse
import jwt
from db import init_table, create_individual, get_all_individuals, get_individual_by_id, update_individual, delete_individual, bulk_upsert_individuals, link_user_by_email, is_in_managers_hierarchy, check_email_exists

logger = logging.getLogger()
logger.setLevel(logging.INFO)

# PostgreSQL connection config from environment variables
IS_LOCAL = os.getenv("IS_LOCAL", "false") == "true"
PG_CONFIG = (
    f"host={os.getenv('POSTGRES_HOST', 'localhost')} "
    f"port={os.getenv('POSTGRES_PORT', '5432')} "
    f"user={os.getenv('POSTGRES_USER', 'postgres')} "
    f"password={os.getenv('POSTGRES_PASS', 'postgres123')} "
    f"dbname={os.getenv('POSTGRES_NAME', 'postgres')} "
    f"connect_timeout=15"
)
if not IS_LOCAL:
    PG_CONFIG += " sslmode=require"

# Initialize table on cold start
_initialized = False

def _ensure_init():
    global _initialized
    if not _initialized:
        init_table(PG_CONFIG)
        _initialized = True

def handler(event=None, context=None):
    """Lambda handler routing by HTTP method."""
    _ensure_init()

    try:
        method = event.get("requestContext", {}).get("http", {}).get("method", "GET")
        path = event.get("rawPath", "")
        query_params = event.get("queryStringParameters") or {}
        body = {}

        if event.get("body"):
            try:
                body = json.loads(event["body"])
            except (json.JSONDecodeError, TypeError):
                return response(400, {"error": "Invalid JSON body"})

        # Extract ID from path: /api/individuals-service/{id}
        resource_id = extract_id(path)

        if method == "POST":
            # Check for specific actions in the body or URL
            if path.endswith("/import"):
                return handle_bulk_import(body)
            elif path.endswith("/link"):
                return handle_jit_link(body)
            elif path.endswith("/sync"):
                return handle_hris_sync()
            return handle_create(body)
        elif method == "GET":
            if path.endswith("/lookup"):
                return handle_lookup(query_params)
            if resource_id:
                return handle_get_one(resource_id)
            return handle_get_all(query_params, event)
        elif method == "PUT":
            if not resource_id:
                return response(400, {"error": "ID is required for update"})
            return handle_update(resource_id, body, event)
        elif method == "DELETE":
            if not resource_id:
                return response(400, {"error": "ID is required for delete"})
            return handle_delete(resource_id)
        else:
            return response(405, {"error": f"Method {method} not allowed"})

    except Exception as e:
        logger.error("Handler error: %s", str(e))
        return response(500, {"error": "Internal server error", "message": str(e)})

def handle_create(body):
    """Handle POST - create a new individual."""
    errors = validate(body)
    if errors:
        return response(400, {"error": "Validation failed", "details": errors})

    try:
        individual = create_individual(PG_CONFIG, body)
        return response(201, individual)
    except Exception as e:
        if "unique" in str(e).lower() or "duplicate" in str(e).lower():
            return response(400, {"error": "An individual with this employee_id or email already exists"})
        raise

def handle_bulk_import(body):
    """Handle POST /api/individuals-service/import"""
    individuals = body.get("individuals", [])
    if not isinstance(individuals, list) or not individuals:
        return response(400, {"error": "Invalid payload. Expected a list of individuals."})

    # In a production app, add validation for required fields (employee_id, first_name, last_name) here.
    try:
        bulk_upsert_individuals(PG_CONFIG, individuals)
        return response(200, {"message": f"Successfully imported/updated {len(individuals)} records."})
    except Exception as e:
        logger.error("Import error: %s", str(e))
        return response(500, {"error": "Failed to process import.", "details": str(e)})

def handle_jit_link(body):
    """Handle POST /api/individuals-service/link (Internal Call from Auth Service)"""
    email = body.get("email")
    user_id = body.get("user_id")

    if not email or not user_id:
        return response(400, {"error": "email and user_id are required"})

    result = link_user_by_email(PG_CONFIG, email, user_id)

    if result:
        return response(200, {"message": "Account linked successfully", "individual": result})
    return response(404, {"message": "No unlinked individual found with that email."})

def handle_hris_sync():
    """Handle POST /api/individuals-service/sync — inline HRIS sync (replaces EventBridge trigger)."""
    logger.info("Starting inline HRIS employee sync...")

    # Mock HRIS data — in production this would call Workday, BambooHR, etc.
    mock_hris_data = [
        {"employee_id": "EMP-001", "email": "jdoe@acme.com", "first_name": "John", "last_name": "Doe", "is_direct_staff": True},
        # Add more mock records as needed for testing
    ]

    try:
        bulk_upsert_individuals(PG_CONFIG, mock_hris_data)
        logger.info(f"HRIS sync complete: {len(mock_hris_data)} records processed.")
        return response(200, {"message": f"Sync complete. {len(mock_hris_data)} records processed.", "count": len(mock_hris_data)})
    except Exception as e:
        logger.error(f"HRIS sync failed: {str(e)}")
        return response(500, {"error": "HRIS sync failed", "message": str(e)})

def get_user_from_event(event):
    """Extract and decode user from Authorization header."""
    auth_header = event.get("headers", {}).get("authorization", event.get("headers", {}).get("Authorization", ""))
    if not auth_header.startswith("Bearer "):
        return None
    try:
        # Secret key should match auth-service
        return jwt.decode(auth_header[7:], os.getenv("JWT_SECRET", "acme-team-mgmt-secret-key-2026"), algorithms=["HS256"])
    except:
        return None

def handle_lookup(params):
    """Handle GET /api/individuals-service/lookup?email=..."""
    email = params.get("email", "").strip().lower()
    if not email:
        return response(400, {"error": "email parameter is required"})

    ind = check_email_exists(PG_CONFIG, email)
    if ind:
        return response(200, {"status": "verified", "designation": ind.get("designation")})
    return response(404, {"error": "Email not found in employee database"})

def handle_get_all(params, event):
    """Handle GET all individuals with RBAC scoping."""
    user = get_user_from_event(event)
    if not user:
        return response(401, {"error": "Unauthorized"})

    team_id = params.get("team_id")
    individuals = get_all_individuals(PG_CONFIG, team_id=team_id, user=user)
    return response(200, individuals)

def handle_get_one(resource_id):
    """Handle GET individual by ID."""
    individual = get_individual_by_id(PG_CONFIG, resource_id)
    if not individual:
        return response(404, {"error": "Individual not found"})
    return response(200, individual)

def handle_update(resource_id, body, event):
    """Handle PUT - update an individual with RBAC/Hierarchy checks."""
    user = get_user_from_event(event)
    if not user:
        return response(401, {"error": "Unauthorized"})

    if user["role"] == "manager":
        # Check if the individual is within the manager's downstream scope
        if not is_in_managers_hierarchy(PG_CONFIG, user["user_id"], resource_id):
            return response(403, {"error": "Hierarchy restriction: This individual is outside your organization."})

    errors = validate(body)
    if errors:
        return response(400, {"error": "Validation failed", "details": errors})

    individual = update_individual(PG_CONFIG, resource_id, body)
    if not individual:
        return response(404, {"error": "Individual not found"})
    return response(200, individual)

def handle_delete(resource_id):
    """Handle DELETE - remove an individual."""
    deleted = delete_individual(PG_CONFIG, resource_id)
    if not deleted:
        return response(404, {"error": "Individual not found"})
    return response(204, None)

def validate(data):
    """Validate individual data."""
    errors = []
    if not data.get("employee_id", "").strip():
        errors.append("employee_id is required")
    if not data.get("first_name", "").strip():
        errors.append("first_name is required")
    if not data.get("last_name", "").strip():
        errors.append("last_name is required")
    return errors

def extract_id(path):
    """Extract resource ID from URL path."""
    parts = [p for p in path.split("/") if p]
    # Path format: /api/individuals-service/{id}
    if len(parts) >= 3 and parts[0] == "api":
        return parts[2]
    return None

def response(status_code, body):
    """Build a Lambda response object."""
    resp = {
        "statusCode": status_code,
        "headers": {
            "Content-Type": "application/json",
            "Access-Control-Allow-Origin": "*",
            "Access-Control-Allow-Methods": "GET, POST, PUT, DELETE, OPTIONS",
            "Access-Control-Allow-Headers": "Content-Type, Authorization",
        },
    }
    if body is not None:
        resp["body"] = json.dumps(body, default=str)
    return resp

if __name__ == "__main__":
    # Local testing
    print(handler({"requestContext": {"http": {"method": "GET"}}, "rawPath": "/api/individuals-service"}, None))

"""
AWS Lambda handler for Skills service.
Provides Skills Catalog, Team Required Skills, Individual Skill Assessments, and Gap Analysis.
"""

import json
import logging
import os
from db import (
    init_table,
    create_catalog_item,
    get_all_catalog_items,
    delete_catalog_item,
    set_team_required_skill,
    get_team_required_skills,
    delete_team_required_skill,
    set_individual_skill,
    get_individual_skills,
    delete_individual_skill,
    get_team_gap_analysis,
)

logger = logging.getLogger()
logger.setLevel(logging.INFO)

IS_LOCAL = os.getenv("IS_LOCAL", "false") == "true"
PG_CONFIG = (
    f"host={os.getenv('POSTGRES_HOST', 'localhost')} "
    f"port={os.getenv('POSTGRES_PORT', '5432')} "
    f"user={os.getenv('POSTGRES_USER', 'postgres')} "
    f"password={os.getenv('POSTGRES_PASS', 'postgres123')} "
    f"dbname={os.getenv('POSTGRES_NAME', 'postgres')} "
    f"connect_timeout=15"
)
if not IS_LOCAL:
    PG_CONFIG += " sslmode=require"

_initialized = False

def _ensure_init():
    global _initialized
    if not _initialized:
        init_table(PG_CONFIG)
        _initialized = True

def handler(event=None, context=None):
    """Lambda handler routing for skills management."""
    _ensure_init()

    try:
        method = event.get("requestContext", {}).get("http", {}).get("method", "GET")
        path = event.get("rawPath", "")
        query_params = event.get("queryStringParameters") or {}
        body = {}

        if event.get("body"):
            try:
                body = json.loads(event["body"])
            except (json.JSONDecodeError, TypeError):
                return response(400, {"error": "Invalid JSON body"})

        # Determine sub-resource from path
        # /api/skills-service/catalog
        # /api/skills-service/team-skills
        # /api/skills-service/individual-skills
        # /api/skills-service/gap-analysis
        parts = [p for p in path.split("/") if p]
        sub_resource = parts[2] if len(parts) > 2 else None
        resource_id = parts[3] if len(parts) > 3 else None

        if method == "POST":
            if sub_resource == "catalog":
                return handle_create_catalog(body)
            elif sub_resource == "team-skills":
                return handle_set_team_skill(body)
            elif sub_resource == "individual-skills":
                return handle_set_individual_skill(body)
            return response(400, {"error": f"Invalid POST path: {path}"})

        elif method == "GET":
            if sub_resource == "catalog":
                return handle_get_catalog()
            elif sub_resource == "team-skills":
                return handle_get_team_skills(query_params)
            elif sub_resource == "individual-skills":
                return handle_get_individual_skills(query_params)
            elif sub_resource == "gap-analysis":
                return handle_gap_analysis(query_params)
            return response(400, {"error": f"Invalid GET path: {path}"})

        elif method == "DELETE":
            if not resource_id:
                return response(400, {"error": "ID is required for delete"})
            if sub_resource == "catalog":
                return handle_delete_catalog(resource_id)
            elif sub_resource == "team-skills":
                return handle_delete_team_skill(resource_id)
            elif sub_resource == "individual-skills":
                return handle_delete_individual_skill(resource_id)
            return response(400, {"error": f"Invalid DELETE path: {path}"})

        else:
            return response(405, {"error": f"Method {method} not allowed"})

    except Exception as e:
        logger.error("Handler error: %s", str(e))
        return response(500, {"error": "Internal server error", "message": str(e)})

# --- Catalog Handlers ---

def handle_create_catalog(body):
    if not body.get("name"):
        return response(400, {"error": "name is required"})
    try:
        item = create_catalog_item(PG_CONFIG, body)
        return response(201, item)
    except Exception as e:
        if "unique" in str(e).lower() or "duplicate" in str(e).lower():
            return response(400, {"error": "A skill with this name already exists"})
        raise

def handle_get_catalog():
    items = get_all_catalog_items(PG_CONFIG)
    return response(200, items)

def handle_delete_catalog(resource_id):
    deleted = delete_catalog_item(PG_CONFIG, resource_id)
    if not deleted:
        return response(404, {"error": "Skill not found"})
    return response(204, None)

# --- Team Skills Handlers ---

def handle_set_team_skill(body):
    if not body.get("team_id") or not body.get("skill_id"):
        return response(400, {"error": "team_id and skill_id are required"})
    item = set_team_required_skill(PG_CONFIG, body)
    return response(201, item)

def handle_get_team_skills(params):
    team_id = params.get("team_id")
    if not team_id:
        return response(400, {"error": "team_id query parameter is required"})
    items = get_team_required_skills(PG_CONFIG, team_id)
    return response(200, items)

def handle_delete_team_skill(resource_id):
    deleted = delete_team_required_skill(PG_CONFIG, resource_id)
    if not deleted:
        return response(404, {"error": "Team skill requirement not found"})
    return response(204, None)

# --- Individual Skills Handlers ---

def handle_set_individual_skill(body):
    if not body.get("individual_id") or not body.get("skill_id"):
        return response(400, {"error": "individual_id and skill_id are required"})
    item = set_individual_skill(PG_CONFIG, body)
    return response(201, item)

def handle_get_individual_skills(params):
    individual_id = params.get("individual_id")
    if not individual_id:
        return response(400, {"error": "individual_id query parameter is required"})
    items = get_individual_skills(PG_CONFIG, individual_id)
    return response(200, items)

def handle_delete_individual_skill(resource_id):
    deleted = delete_individual_skill(PG_CONFIG, resource_id)
    if not deleted:
        return response(404, {"error": "Individual skill record not found"})
    return response(204, None)

# --- Gap Analysis Handler ---

def handle_gap_analysis(params):
    team_id = params.get("team_id")
    if not team_id:
        return response(400, {"error": "team_id query parameter is required"})
    analysis = get_team_gap_analysis(PG_CONFIG, team_id)
    return response(200, analysis)

# --- Utilities ---

def response(status_code, body):
    """Build a Lambda response object."""
    resp = {
        "statusCode": status_code,
        "headers": {
            "Content-Type": "application/json",
            "Access-Control-Allow-Origin": "*",
            "Access-Control-Allow-Methods": "GET, POST, PUT, DELETE, OPTIONS",
            "Access-Control-Allow-Headers": "Content-Type, Authorization",
        },
    }
    if body is not None:
        resp["body"] = json.dumps(body, default=str)
    return resp

if __name__ == "__main__":
    print(handler({"requestContext": {"http": {"method": "GET"}}, "rawPath": "/api/skills-service/catalog"}, None))

