];

const EMPTY_FORM = { employee_id: '', email: '', first_name: '', last_name: '', is_direct_staff: true, designation: '', location: '' };

export default function HRISConsolePage() {
  const theme = useTheme();
  const [hrisData, setHrisData] = useState(INITIAL_HRIS_DATA);
  const [dialogOpen, setDialogOpen] = useState(false);
  const [editingIndex, setEditingIndex] = useState(null);
  const [form, setForm] = useState(EMPTY_FORM);
  const [errors, setErrors] = useState({});
  const [syncing, setSyncing] = useState(false);
  const [syncResult, setSyncResult] = useState(null);
  const [snack, setSnack] = useState({ open: false, message: '', severity: 'success' });

  const handleOpen = (index = null) => {
    if (index !== null) {
      setEditingIndex(index);
      setForm({ ...hrisData[index] });
    } else {
      setEditingIndex(null);
      const nextId = `EMP-${String(hrisData.length + 1).padStart(3, '0')}`;
      setForm({ ...EMPTY_FORM, employee_id: nextId });
    }
    setErrors({});
    setDialogOpen(true);
  };

  const validate = () => {
    const e = {};
    if (!form.employee_id.trim()) e.employee_id = 'Required';
    if (!form.first_name.trim()) e.first_name = 'Required';
    if (!form.last_name.trim()) e.last_name = 'Required';
    if (!form.email.trim()) e.email = 'Required';
    else if (!form.email.includes('@')) e.email = 'Invalid email';
    const dupIndex = hrisData.findIndex(d => d.employee_id === form.employee_id);
    if (dupIndex !== -1 && dupIndex !== editingIndex) e.employee_id = 'Duplicate ID';
    setErrors(e);
    return Object.keys(e).length === 0;
  };

  const handleSave = () => {
    if (!validate()) return;
    if (editingIndex !== null) {
      const updated = [...hrisData];
      updated[editingIndex] = { ...form };
      setHrisData(updated);
      showSnack('Record updated');
    } else {
      setHrisData([...hrisData, { ...form }]);
      showSnack('Record added');
    }
    setDialogOpen(false);
  };

  const handleDelete = (index) => {
    setHrisData(hrisData.filter((_, i) => i !== index));
    showSnack('Record removed');
  };

  const handleSync = async () => {
    if (hrisData.length === 0) {
      showSnack('No records to sync', 'warning');
      return;
    }

    setSyncing(true);
    setSyncResult(null);

    try {
      // Intercept and resolve locations sequentially to respect API rate limits
      const enrichedData = [];
      for (let i = 0; i < hrisData.length; i++) {
        const emp = hrisData[i];
        if (emp.location) {
          const coords = await geocodeLocation(emp.location);
          enrichedData.push({ ...emp, location_lat: coords.lat, location_lng: coords.lng });

          // Delay 1.1 seconds between requests (Nominatim limit is 1 req/sec)
          // We skip the delay on the final iteration to save time
          if (i < hrisData.length - 1) {
            await new Promise(resolve => setTimeout(resolve, 1100));
          }
        } else {
          enrichedData.push(emp);
        }
      }

      const apiUrl = import.meta.env.VITE_API_URL || 'http://localhost:3001';
      const response = await axios.post(
        `${apiUrl}/api/individuals-service/import`,
        { individuals: enrichedData },
        { headers: { Authorization: `Bearer ${localStorage.getItem('token')}` } }
      );

      setSyncResult({
        success: true,
        message: response.data.message || `Successfully synced ${hrisData.length} records`,
        timestamp: new Date().toLocaleTimeString(),
      });
      showSnack('Sync completed successfully!');
    } catch (error) {
      const errorMsg = error.response?.data?.error || error.message || 'Sync failed';
      setSyncResult({
        success: false,
        message: errorMsg,
        timestamp: new Date().toLocaleTimeString(),
      });
      showSnack(errorMsg, 'error');
    } finally {
      setSyncing(false);
    }
  };

  const showSnack = (message, severity = 'success') => setSnack({ open: true, message, severity });

  return (




             HRIS Simulation Console


            Simulate the external HRIS database and test employee sync operations




      {/* Control Panel */}




               Sync Control


              Push {hrisData.length} records to the Individuals Service via /api/individuals-service/import


          <Button
            variant="contained"
            startIcon={syncing ?  : }
            onClick={handleSync}
            disabled={syncing}
            sx={{
              borderRadius: 2, textTransform: 'none', fontWeight: 700, px: 4, py: 1.2,
              background: theme.palette.mode === 'light'
                ? 'linear-gradient(135deg, #10b981 0%, #059669 100%)'
                : 'linear-gradient(135deg, #059669 0%, #047857 100%)',
              boxShadow: theme.palette.mode === 'light' 
                ? '0 4px 14px rgba(16,185,129,0.4)'
                : '0 4px 14px rgba(0,0,0,0.4)',
              fontSize: '0.95rem',
            }}
          >
            {syncing ? 'Syncing...' : 'Trigger Sync'}



        {syncResult && (
          <Alert
            severity={syncResult.success ? 'success' : 'error'}
            icon={syncResult.success ?  : undefined}
            sx={{ mt: 2, borderRadius: 2 }}
          >

              {syncResult.message}


              {syncResult.timestamp}


        )}


      {/* HRIS Data Table */}




              Simulated HRIS Records



          <Button variant="outlined" startIcon={} onClick={() => handleOpen()}
            sx={{
              borderRadius: 2, textTransform: 'none', fontWeight: 600,
              borderColor: 'success.main', color: 'success.main',
              '&:hover': { borderColor: 'success.dark', bgcolor: `${theme.palette.success.main}08` },
            }}
          >
            Add Employee







                Employee ID
                Name
                Email
                Designation
                Staff Type
                Actions



              {hrisData.length === 0 ? (


                    No HRIS records. Add some employees to test sync.


              ) : (
                hrisData.map((record, index) => (






                        {record.first_name} {record.last_name}


                    {record.email}


                        {record.designation || 'Pending'}







                         handleOpen(index)} sx={{ color: 'primary.main', mr: 0.5 }}>




                         handleDelete(index)} sx={{ color: 'error.main' }}>





                ))
              )}





      {/* How it works */}


          How This Works


          {[
            { step: '1', text: 'Add, edit, or remove employee records in the simulated HRIS database above.' },
            { step: '2', text: 'Click "Trigger Sync" to push all records to the Individuals Service via the /import endpoint.' },
            { step: '3', text: 'The service performs an upsert — new records are created, existing ones (by employee_id) are updated.' },
            { step: '4', text: 'Navigate to the Individuals page to verify the synced data.' },
          ].map(item => (


              {item.text}

          ))}



      {/* Add/Edit Dialog */}
       setDialogOpen(false)} maxWidth="sm" fullWidth PaperProps={{ sx: { borderRadius: 3 } }}>

          {editingIndex !== null ? 'Edit HRIS Record' : 'Add HRIS Record'}


           setForm({ ...form, employee_id: e.target.value })}
            error={!!errors.employee_id} helperText={errors.employee_id}
            sx={{ mb: 2, '& .MuiOutlinedInput-root': { borderRadius: 2 } }}
            placeholder="e.g. EMP-009"
          />

             setForm({ ...form, first_name: e.target.value })}
              error={!!errors.first_name} helperText={errors.first_name}
              sx={{ '& .MuiOutlinedInput-root': { borderRadius: 2 } }}
            />
             setForm({ ...form, last_name: e.target.value })}
              error={!!errors.last_name} helperText={errors.last_name}
              sx={{ '& .MuiOutlinedInput-root': { borderRadius: 2 } }}
            />

           setForm({ ...form, email: e.target.value })}
            error={!!errors.email} helperText={errors.email}
            sx={{ mb: 2, '& .MuiOutlinedInput-root': { borderRadius: 2 } }}
            placeholder="e.g. name@acme.com"
          />
           setForm({ ...form, designation: e.target.value })}
            sx={{ mb: 2, '& .MuiOutlinedInput-root': { borderRadius: 2 } }}
            placeholder="e.g. Senior Software Engineer"
          />
           setForm({ ...form, location: e.target.value })}
            sx={{ mb: 2, '& .MuiOutlinedInput-root': { borderRadius: 2 } }}
            placeholder="e.g. San Francisco, CA"
          />
          <FormControlLabel
            control={ setForm({ ...form, is_direct_staff: !e.target.checked })} />}
            label="Indirect Staff"
          />


           setDialogOpen(false)} sx={{ borderRadius: 2 }}>Cancel

            {editingIndex !== null ? 'Update' : 'Add'}




       setSnack({ ...snack, open: false })}
        anchorOrigin={{ vertical: 'bottom', horizontal: 'right' }}>
         setSnack({ ...snack, open: false })} sx={{ borderRadius: 2 }}>{snack.message}


  );
}

import { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import {
  Box, Card, CardContent, TextField, Button, Typography, Alert,
  InputAdornment, IconButton, Tabs, Tab, CircularProgress, useTheme,
} from '@mui/material';
import {
  Visibility, VisibilityOff, Groups as GroupsIcon,
  Email as EmailIcon, Person as PersonIcon, Lock as LockIcon,
} from '@mui/icons-material';
import authService from '../services/authService';
import logo from '../assets/logo.png';
import { useColorMode } from '../contexts/ColorModeContext';

export default function LoginPage() {
  const [tab, setTab] = useState(0);
  const [form, setForm] = useState({ username: '', email: '', password: '' });
  const [showPassword, setShowPassword] = useState(false);
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();
  const theme = useTheme();
  const { mode } = useColorMode();

  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
    setError('');
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setLoading(true);
    try {
      if (tab === 0) {
        await authService.login(form.username, form.password);
        navigate('/');
      } else {
        if (!form.email) { setError('Email is required'); setLoading(false); return; }
        // --- NEW CLIENT-SIDE VALIDATION ---
        if (!form.email.toLowerCase().endsWith('@acme.com')) {
          setError('You must use your official @acme.com email to register.');
          setLoading(false);
          return;
        }
        // ----------------------------------
        await authService.register(form.username, form.email, form.password);
        navigate('/?new=1');
      }
    } catch (err) {
      if (err.response?.data?.details) {
        setError(err.response.data.details.join(', '));
      } else {
