export default function ProtectedRoute({ children, requiredRoles = [] }) {
  if (!authService.isAuthenticated()) {
    return ;
  }

  if (requiredRoles.length > 0 && !authService.hasRole(requiredRoles)) {
    return ;
  }

  return children;
}

