resource "aws_cloudfront_origin_access_control" "this" {
  count                             = data.aws_caller_identity.this.id != "000000000000" ? 1 : 0
  name                              = local.origin_id
  origin_access_control_origin_type = "s3"
  signing_behavior                  = "always"
  signing_protocol                  = "sigv4"
}

resource "aws_cloudfront_distribution" "this" {
  count               = data.aws_caller_identity.this.id != "000000000000" ? 1 : 0
  enabled             = true
  is_ipv6_enabled     = true
  default_root_object = "index.html"
  price_class         = "PriceClass_200"

  origin {
    domain_name              = aws_s3_bucket.this.bucket_regional_domain_name
    origin_id                = local.origin_id
    origin_access_control_id = element(aws_cloudfront_origin_access_control.this.*.id, count.index)
  }

  dynamic "origin" {
    for_each = local.function_origins
    content {
      domain_name = origin.value.domain_name
      origin_id   = origin.value.origin_id

      custom_header {
        name  = "X-Forwarded-Host"
        value = origin.value.domain_name
      }

      custom_origin_config {
        http_port              = 80
        https_port             = 443
        origin_protocol_policy = "https-only"
        origin_ssl_protocols   = ["TLSv1.2"]
      }
    }
  }

  custom_error_response {
    error_code            = 404
    error_caching_min_ttl = 300
    response_code         = 200
    response_page_path    = "/index.html"
  }

  custom_error_response {
    error_code            = 403
    error_caching_min_ttl = 300
    response_code         = 200
    response_page_path    = "/index.html"
  }

  # logging_config {
  #   include_cookies = false
  #   bucket          = var.aws_bucket
  #   prefix          = "cdn_website_logs/"
  # }

  dynamic "ordered_cache_behavior" {
    for_each = local.function_origins
    content {
      path_pattern     = "/api/${ordered_cache_behavior.value.name}*"
      target_origin_id = ordered_cache_behavior.value.origin_id

      allowed_methods        = ["GET", "HEAD", "OPTIONS", "DELETE", "PATCH", "POST", "PUT"]
      cached_methods         = ["GET", "HEAD"]
      viewer_protocol_policy = "redirect-to-https"

      # Use managed cache policy for no caching (ID: 4135ea2d-6df8-44a3-9df3-4b5a84be39ad)
      cache_policy_id = "4135ea2d-6df8-44a3-9df3-4b5a84be39ad"

      # Use managed origin request policy - AllViewerExceptHostHeader
      # This forwards all viewer headers EXCEPT Host, so Lambda Function URLs get the correct Host header
      # (ID: b689b0a8-53d0-40ab-baf2-68738e2966ac = AllViewerExceptHostHeader)
      origin_request_policy_id = "b689b0a8-53d0-40ab-baf2-68738e2966ac"

      # Legacy cache settings (commented out - using managed policies above)
      # min_ttl     = 0
      # default_ttl = 0
      # max_ttl     = 0

      # forwarded_values {
      #   query_string = true
      #   headers      = ["*"]

      #   cookies {
      #     forward = "all"
      #   }
      # }
    }
  }

  default_cache_behavior {
    allowed_methods = ["GET", "HEAD", "OPTIONS"]
    cached_methods  = ["GET", "HEAD"]

    default_ttl = 3600
    max_ttl     = 86400
    min_ttl     = 0

    target_origin_id       = local.origin_id
    viewer_protocol_policy = "redirect-to-https"

    forwarded_values {
      query_string = false

      cookies {
        forward = "none"
      }
    }
  }

  restrictions {
    geo_restriction {
      restriction_type = "none"
    }
  }

  viewer_certificate {
    cloudfront_default_certificate = true
  }

  tags = local.app_tags
}

resource "aws_s3_bucket_policy" "this" {
  count  = data.aws_caller_identity.this.id != "000000000000" ? 1 : 0
  bucket = aws_s3_bucket.this.id
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid    = "AllowCloudFrontServicePrincipal"
        Effect = "Allow"
        Principal = {
          Service = data.aws_service_principal.cloudfront.name
        }
        Action   = "s3:GetObject"
        Resource = format("%s/*", aws_s3_bucket.this.arn)
        Condition = {
          StringEquals = {
            "AWS:SourceArn" = format(
              "arn:aws:cloudfront::%s:distribution/%s",
              data.aws_caller_identity.this.account_id,
              element(aws_cloudfront_distribution.this.*.id, count.index)
            )
          }
        }
      }
    ]
  })
}

data "aws_region" "this" {}
data "aws_partition" "this" {}
data "aws_caller_identity" "this" {}

data "aws_vpcs" "this" {
  filter {
    name   = "vpc-id"
    values = [try(trimspace(var.aws_vpc_id), "") != "" ? trimspace(var.aws_vpc_id) : "*"]
  }
}

data "aws_vpc" "this" {
  id      = try(element(data.aws_vpcs.this.ids, 0), null)
  default = try(element(data.aws_vpcs.this.ids, 0), null) != null ? false : true
}

data "aws_availability_zones" "this" {
  filter {
    name   = "zone-type"
    values = ["availability-zone"]
  }
  filter {
    name   = "state"
    values = ["available"]
  }
}

data "aws_subnets" "this" {
  filter {
    name   = "vpc-id"
    values = [data.aws_vpc.this.id]
  }
  filter {
    name   = "availability-zone-id"
    values = data.aws_availability_zones.this.zone_ids
  }
}

data "aws_route_tables" "this" {
  filter {
    name   = "vpc-id"
    values = [data.aws_vpc.this.id]
  }
}

data "aws_route_table" "this" {
  for_each       = toset(data.aws_route_tables.this.ids)
  route_table_id = each.value
}

data "aws_security_groups" "this" {
  filter {
    name   = "vpc-id"
    values = [data.aws_vpc.this.id]
  }
  filter {
    name   = "group-name"
    values = [format("*%s*", local.app_id)]
  }
}

data "aws_service_principal" "cloudfront" {
  service_name = "cloudfront"
  region       = data.aws_region.this.region
}

data "aws_servicecatalogappregistry_application" "this" {
  count  = data.aws_caller_identity.this.id != "000000000000" && try(var.aws_app_code, null) != null ? 1 : 0
  id     = format("%s-%s", var.aws_project, var.aws_app_code)
  region = data.aws_region.this.region
}

resource "random_id" "this" {
  byte_length = 4

  keepers = {
    seed_input = try(var.aws_app_code, terraform.workspace)
  }
}

resource "random_pet" "this" {
  length    = 3
  separator = "-"

  keepers = {
    seed_input = try(var.aws_app_code, terraform.workspace)
  }
}

provider "aws" {
  default_tags {
    tags = {
      application = "coding-workshop"
      contact     = "github.com/eistrati"
      environment = terraform.workspace
    }
  }

  skip_credentials_validation = true
  skip_metadata_api_check     = true
  skip_region_validation      = true
}

terraform {
  backend "s3" {
    bucket = "coding-workshop-us-east-1-abcd1234"
    key    = "terraform/terraform.tfstate"
  }

  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 6.0"
    }
    external = {
      source  = "hashicorp/external"
      version = "~> 2.0"
    }
    local = {
      source  = "hashicorp/local"
      version = "~> 2.0"
    }
    null = {
      source  = "hashicorp/null"
      version = "~> 3.0"
    }
    random = {
      source  = "hashicorp/random"
      version = "~> 3.0"
    }
  }

  required_version = ">= 1.11.0"
}

locals {
  app_id = try(trimspace(var.aws_app_code), "") != "" ? trimspace(var.aws_app_code) : random_id.this.hex
  app_tags = merge(
    try(element(data.aws_servicecatalogappregistry_application.this.*.application_tag, 0), {}),
    { participant = local.app_id, event = random_id.this.hex }
  )
  public_route_table_ids = [
    for rt in data.aws_route_table.this :
    rt.id if length([for route in rt.routes : route if startswith(route.gateway_id, "igw-")]) > 0
  ]
  public_subnet_ids = sort(distinct(flatten([
    for rt_id in local.public_route_table_ids : [
      for assoc in data.aws_route_table.this[rt_id].associations :
      assoc.subnet_id if assoc.subnet_id != ""
    ]
  ])))
  private_subnet_ids = sort(tolist(setsubtract(data.aws_subnets.this.ids, local.public_subnet_ids)))
  java_dirs = [
    for file in fileset(format("%s/../backend", path.module), "*/pom.xml") :
    dirname(file) if !startswith(dirname(file), "_") && !startswith(dirname(file), ".")
  ]
  nodejs_dirs = [
    for file in fileset(format("%s/../backend", path.module), "*/package.json") :
    dirname(file) if !startswith(dirname(file), "_") && !startswith(dirname(file), ".")
  ]
  python_dirs = [
    for file in fileset(format("%s/../backend", path.module), "*/function.py") :
    dirname(file) if !startswith(dirname(file), "_") && !startswith(dirname(file), ".")
  ]
  java_names = {
    for name in local.java_dirs : name => {
      name    = name
      arch    = "x86_64"
      runtime = "java25"
      handler = "com.example.Handler::handleRequest"
      path    = abspath(format("%s/../backend/%s/target", path.module, name))
      mvn_cmd = [
        format("cd %s", abspath(format("%s/../backend/%s", path.module, name))),
        "mvn clean package -DskipTests",
        format("find ./target ! -name '%s*.jar' -delete", name),
      ]
    }
  }
  nodejs_names = {
    for name in local.nodejs_dirs : name => {
      name             = name
      arch             = "x86_64"
      runtime          = "nodejs24.x"
      handler          = "index.handler"
      path             = abspath(format("%s/../backend/%s", path.module, name))
      patterns         = ["node_modules/.+"]
      npm_requirements = true
    }
  }
  python_names = {
    for name in local.python_dirs : name => {
      name             = name
      arch             = "x86_64"
      runtime          = "python3.11"
      handler          = "function.handler"
      path             = abspath(format("%s/../backend/%s", path.module, name))
      patterns         = ["!__pycache__/.*", "!\\..*"]
      pip_requirements = true
    }
  }
  function_names = merge(local.java_names, local.nodejs_names, local.python_names)
  function_origins = [
    for name, func in local.function_names : {
      name        = func.name
      origin_id   = format("lambda-%s", func.name)
      domain_name = replace(replace(module.lambda[name].lambda_function_url, "https://", ""), "/", "")
    }
  ]
  origin_id = format("%s-s3-origin-%s", var.aws_project, local.app_id)
  env_vars = {
    APP_ID        = local.app_id
    APP_NAME      = format("%s-%s", var.aws_project, local.app_id)
    APP_ROLE      = format("arn:%s:iam::%s:role/%s-assume-%s", data.aws_partition.this.partition, data.aws_caller_identity.this.account_id, var.aws_project, local.app_id)
    APP_REGION    = data.aws_region.this.region
    IS_LOCAL      = data.aws_caller_identity.this.id == "000000000000" ? "true" : "false"
    POSTGRES_HOST = data.aws_caller_identity.this.id == "000000000000" ? coalesce(try(trimspace(var.aws_postgres_host), ""), "172.17.0.1") : element(aws_rds_cluster.this.*.endpoint, 0)
    POSTGRES_PORT = data.aws_caller_identity.this.id == "000000000000" ? "5432" : element(aws_rds_cluster.this.*.port, 0)
    POSTGRES_NAME = data.aws_caller_identity.this.id == "000000000000" ? "postgres" : element(aws_rds_cluster.this.*.database_name, 0)
    POSTGRES_USER = data.aws_caller_identity.this.id == "000000000000" ? "postgres" : element(aws_rds_cluster.this.*.master_username, 0)
    POSTGRES_PASS = data.aws_caller_identity.this.id == "000000000000" ? "postgres123" : element(aws_rds_cluster.this.*.master_password, 0)
    MONGO_HOST    = data.aws_caller_identity.this.id == "000000000000" ? coalesce(try(trimspace(var.aws_mongo_host), ""), "172.17.0.1") : try(element(aws_docdb_cluster.this.*.endpoint, 0), "")
    MONGO_PORT    = data.aws_caller_identity.this.id == "000000000000" ? "27017" : try(element(aws_docdb_cluster.this.*.port, 0), "")
    MONGO_NAME    = data.aws_caller_identity.this.id == "000000000000" ? "mongo" : try(element(aws_docdb_cluster.this.*.database_name, 0), "")
    MONGO_USER              = data.aws_caller_identity.this.id == "000000000000" ? "" : try(element(aws_docdb_cluster.this.*.master_username, 0), "")
    MONGO_PASS              = data.aws_caller_identity.this.id == "000000000000" ? "" : try(element(aws_docdb_cluster.this.*.master_password, 0), "")
    INDIVIDUALS_SERVICE_URL = "http://localhost:8080/api/individuals-service"
  }
  iam_arns = [
    format("arn:%s:iam::aws:policy/service-role/AWSLambdaVPCAccessExecutionRole", data.aws_partition.this.partition),
  ]
}

output "api_base_url" {
  description = "Base URL for API calls (for frontend REACT_APP_API_URL)"
  value       = data.aws_caller_identity.this.id == "000000000000" ? "" : try("https://${element(aws_cloudfront_distribution.this.*.domain_name, 0)}", "")
}

output "api_endpoints" {
  description = "Available API endpoints by function name"
  value = {
    for name, func in local.function_names :
    func.name => data.aws_caller_identity.this.id == "000000000000" ? module.lambda[name].lambda_function_url : "/api/${func.name}"
  }
}

output "cloudfront_distribution_id" {
  description = "The ID of the CloudFront distribution"
  value       = try(element(aws_cloudfront_distribution.this.*.id, 0), null)
}

output "cloudfront_distribution_url" {
  description = "The URL of the CloudFront distribution"
  value       = try(element(aws_cloudfront_distribution.this.*.domain_name, 0), null)
}

output "lambda_urls" {
  description = "The URLs of the Lambda functions"
  value       = { for name, lambda in module.lambda : lambda.lambda_function_name => lambda.lambda_function_url }
}

output "s3_bucket_id" {
  description = "The ID of the S3 bucket"
  value       = aws_s3_bucket.this.id
}

output "s3_bucket_name" {
  description = "The name of the S3 bucket"
  value       = aws_s3_bucket.this.bucket
}

output "website_url" {
  description = "The URL of the website"
  value       = data.aws_caller_identity.this.id == "000000000000" ? "http://${aws_s3_bucket.this.bucket}.s3-website.localhost.localstack.cloud:4566" : try("https://${element(aws_cloudfront_distribution.this.*.domain_name, 0)}", null)
}

resource "aws_db_subnet_group" "this" { count = data.aws_caller_identity.this.id != "000000000000" ? 1 : 0 name = format("%s-rds-subnet-group-%s", var.aws_project, local.app_id) subnet_ids = local.public_subnet_ids
tags = local.app_tags }
resource "aws_rds_cluster" "this" { count = data.aws_caller_identity.this.id != "000000000000" ? 1 : 0 cluster_identifier = format("%s-rds-%s", var.aws_project, local.app_id) engine = "aurora-postgresql" engine_mode = "provisioned" engine_version = "17.7" master_username = "superadmin" master_password = random_pet.this.id database_name = replace(var.aws_project, "-", "") backup_retention_period = 7 preferred_backup_window = "07:00-09:00" skip_final_snapshot = true storage_encrypted = true db_subnet_group_name = element(aws_db_subnet_group.this.*.name, count.index) vpc_security_group_ids = data.aws_security_groups.this.ids enabled_cloudwatch_logs_exports = ["postgresql"]
serverlessv2_scaling_configuration { max_capacity = 4.0 min_capacity = 0.0 }
tags = local.app_tags }
resource "aws_rds_cluster_instance" "this" { count = data.aws_caller_identity.this.id != "000000000000" ? 1 : 0 cluster_identifier = element(aws_rds_cluster.this.*.id, count.index) engine = element(aws_rds_cluster.this.*.engine, count.index) engine_version = element(aws_rds_cluster.this.*.engine_version, count.index) identifier = format("%s-rds-%s", var.aws_project, local.app_id) instance_class = "db.serverless" auto_minor_version_upgrade = true
tags = local.app_tags }

variable "aws_project" {
  description = "The AWS project name."
  type        = string
  default     = "coding-workshop"
}

variable "aws_bucket" {
  description = "The AWS S3 bucket name for terraform state storage."
  type        = string
  default     = "coding-workshop-us-east-1-abcd1234"
}

variable "aws_app_code" {
  description = "The AWS application unique code."
  type        = string
  default     = "abcd1234"
}

variable "aws_vpc_id" {
  description = "The AWS VPC identifier."
  type        = string
  default     = null
}

variable "aws_docdb_enabled" {
  description = "Enable or disable MongoDB. Set to 'true' to enable it."
  type        = bool
  default     = false
}

variable "aws_mongo_host" {
  description = "MongoDB host for LocalStack. Defaults to 'host.docker.internal' (on Linux, set to '172.17.0.1')."
  type        = string
  default     = null
}

variable "aws_postgres_host" {
  description = "PostgreSQL host for LocalStack. Defaults to 'host.docker.internal' (on Linux, set to '172.17.0.1')."
  type        = string
  default     = null
}

module "lambda" {
  for_each = local.function_names
  source   = "terraform-aws-modules/lambda/aws"
  version  = "~> 8.0"

  function_name   = format("%s-%s-%s", var.aws_project, each.value.name, local.app_id)
  package_type    = "Zip"
  architectures   = [each.value.arch]
  handler         = each.value.handler
  runtime         = each.value.runtime
  memory_size     = 128
  timeout         = 300
  tracing_mode    = "PassThrough"
  build_in_docker = false
  store_on_s3     = data.aws_caller_identity.this.id != "000000000000"
  s3_bucket       = data.aws_caller_identity.this.id != "000000000000" ? aws_s3_bucket.this.id : null
  s3_prefix       = data.aws_caller_identity.this.id != "000000000000" ? format("lambda/%s/%s/", local.app_id, each.value.name) : null

  source_path = [{
    path             = try(each.value.path, null)
    patterns         = try(each.value.patterns, null)
    pip_requirements = try(each.value.pip_requirements, null)
    npm_requirements = try(each.value.npm_requirements, null)
  }]

  vpc_security_group_ids = data.aws_security_groups.this.ids
  vpc_subnet_ids         = local.public_subnet_ids
  attach_network_policy  = true

  create_package     = true
  create_role        = true
  role_name          = format("%s-%s-%s", var.aws_project, each.value.name, local.app_id)
  role_path          = "/service-role/"
  attach_policies    = true
  number_of_policies = length(local.iam_arns)
  policies           = local.iam_arns
  attach_policy_json = true
  policy_json        = templatefile("${path.module}/policy.tftpl", { app_id = local.app_id, app_name = var.aws_project })

  attach_cloudwatch_logs_policy     = true
  attach_dead_letter_policy         = true
  ephemeral_storage_size            = 512
  cloudwatch_logs_retention_in_days = 7
  cloudwatch_logs_skip_destroy      = false
  use_existing_cloudwatch_log_group = false
  trigger_on_package_timestamp      = false
  create_lambda_function_url        = true
  authorization_type                = "NONE"
  dead_letter_target_arn            = aws_sqs_queue.this[each.key].arn

  cors = {
    allow_credentials = false
    allow_headers     = ["*"]
    allow_methods     = ["*"]
    allow_origins     = ["*"]
    expose_headers    = []
    max_age           = 0
  }

  environment_variables = {
    for key, value in local.env_vars :
    key => trimspace(value) if try(trimspace(value), "") != ""
  }

  tags = local.app_tags

  depends_on = [null_resource.java_build]
}

resource "aws_sqs_queue" "this" {
  for_each = local.function_names
  name     = format("%s-%s-dlq-%s", var.aws_project, each.value.name, local.app_id)

  sqs_managed_sse_enabled = true

  tags = local.app_tags
}

resource "null_resource" "hot_reload" {
  for_each = {for k, v in local.function_names : k => v if data.aws_caller_identity.this.id == "000000000000"}

  triggers = {
    source_code_hash = module.lambda[each.key].lambda_function_source_code_hash
  }

  provisioner "local-exec" {
    command = <<-EOT
      AWS_REGION=us-east-1 \
      AWS_ACCESS_KEY_ID=test \
      AWS_SECRET_ACCESS_KEY=test \
      AWS_ENDPOINT_URL=http://localhost:4566 \
      aws lambda update-function-code \
        --function-name ${module.lambda[each.key].lambda_function_name} \
        --s3-bucket hot-reload \
        --s3-key ${each.value.path}
    EOT
  }

  depends_on = [module.lambda, aws_s3_bucket.hot_reload]
}

resource "null_resource" "java_build" {
  for_each = local.java_names

  triggers = {
    source_code_hash = md5(jsonencode({
      for file in fileset(format("%s/../backend/%s", path.module, each.key), "**/*") :
      file => {
        size = try(filesize(format("%s/../backend/%s/%s", path.module, each.key, file)), 0)
      }
    }))
  }

  provisioner "local-exec" {
    command = join(" && ", each.value.mvn_cmd)
  }
}

resource "aws_docdb_subnet_group" "this" { count = data.aws_caller_identity.this.id != "000000000000" && var.aws_docdb_enabled ? 1 : 0 name = format("%s-docdb-subnet-group-%s", var.aws_project, local.app_id) subnet_ids = local.public_subnet_ids
tags = local.app_tags }
resource "aws_docdb_cluster" "this" { count = data.aws_caller_identity.this.id != "000000000000" && var.aws_docdb_enabled ? 1 : 0 cluster_identifier = format("%s-docdb-%s", var.aws_project, local.app_id) engine = "docdb" engine_version = "5.0.0" master_username = "superadmin" master_password = random_pet.this.id backup_retention_period = 7 preferred_backup_window = "07:00-09:00" skip_final_snapshot = true storage_encrypted = true db_subnet_group_name = element(aws_docdb_subnet_group.this.*.name, count.index) vpc_security_group_ids = data.aws_security_groups.this.ids enabled_cloudwatch_logs_exports = ["audit", "profiler"]
serverless_v2_scaling_configuration { max_capacity = 4.0 min_capacity = 0.5 }
tags = local.app_tags }
resource "aws_docdb_cluster_instance" "this" { count = data.aws_caller_identity.this.id != "000000000000" && var.aws_docdb_enabled ? 1 : 0 cluster_identifier = element(aws_docdb_cluster.this.*.id, count.index) engine = element(aws_docdb_cluster.this.*.engine, count.index) identifier = format("%s-docdb-%s", var.aws_project, local.app_id) instance_class = "db.serverless" auto_minor_version_upgrade = true
tags = local.app_tags }

resource "aws_s3_bucket" "hot_reload" {
  count         = data.aws_caller_identity.this.id == "000000000000" ? 1 : 0
  bucket        = "hot-reload"
  force_destroy = true

  lifecycle {
    prevent_destroy = false
  }
}

resource "aws_s3_bucket" "this" {
  bucket        = format("%s-website-%s", var.aws_project, local.app_id)
  force_destroy = true

  lifecycle {
    prevent_destroy = false
  }

  tags = local.app_tags
}

resource "aws_s3_bucket_ownership_controls" "this" {
  bucket = aws_s3_bucket.this.id

  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

resource "aws_s3_bucket_acl" "this" {
  bucket = aws_s3_bucket.this.id
  acl    = "private"

  depends_on = [aws_s3_bucket_ownership_controls.this]
}

# resource "aws_s3_bucket_logging" "this" {
#   bucket        = aws_s3_bucket.this.id
#   target_bucket = var.aws_bucket
#   target_prefix = "s3_website_logs/"
# }

resource "aws_s3_bucket_website_configuration" "this" {
  bucket = aws_s3_bucket.this.id

  index_document {
    suffix = "index.html"
  }

  error_document {
    key = "index.html"
  }
}

#!/usr/bin/env node

/**
 * Development CORS Proxy Server
 *
 * This proxy server forwards requests from the React frontend (localhost:3000)
 * to Lambda Function URLs in LocalStack, working around CORS issues.
 *
 * Only needed for LocalStack development. AWS production handles CORS correctly.
 */

const http = require('http');
const https = require('https');
const url = require('url');
const fs = require('fs');
const path = require('path');

const PORT = 3001;

// Read endpoint mappings from .env.local
const envFile = path.join(__dirname, '../frontend/.env.local');
let endpoints = {};

try {
  const envContent = fs.readFileSync(envFile, 'utf8');
  const match = envContent.match(/VITE_API_ENDPOINTS='(.+)'/) || envContent.match(/REACT_APP_API_ENDPOINTS='(.+)'/);
  if (match) {
    endpoints = JSON.parse(match[1]);
    console.log('Loaded endpoints:', Object.keys(endpoints));
  }
} catch (err) {
  console.error('Could not load endpoints from .env.local:', err.message);
  console.error('Make sure to run: ./bin/generate-env.sh first');
  process.exit(1);
}

const server = http.createServer((req, res) => {
  // Enable CORS
  res.setHeader('Access-Control-Allow-Origin', '*');
  res.setHeader('Access-Control-Allow-Methods', 'GET, POST, PUT, DELETE, PATCH, OPTIONS');
  res.setHeader('Access-Control-Allow-Headers', '*');
  res.setHeader('Access-Control-Max-Age', '86400');

  // Handle preflight
  if (req.method === 'OPTIONS') {
    res.writeHead(204);
    res.end();
    return;
  }

  // Parse request path: /api/{endpoint_name}
  const parsedUrl = url.parse(req.url);
  const pathParts = parsedUrl.pathname.split('/').filter(Boolean);

  if (pathParts[0] !== 'api' || pathParts.length < 2) {
    res.writeHead(200, { 'Content-Type': 'application/json' });
    res.end(JSON.stringify({
      message: 'Development CORS Proxy Server',
      usage: 'GET /api/{endpoint_name}',
      endpoints: Object.keys(endpoints).map(name => `http://localhost:${PORT}/api/${name}`)
    }, null, 2));
    return;
  }

  const endpointName = pathParts[1];
  const remainingPath = '/' + pathParts.join('/');
  const baseUrl = (endpoints[endpointName] || '').replace(/\/$/, '');
  const targetUrl = baseUrl + remainingPath + (parsedUrl.search || '');

  if (!targetUrl) {
    res.writeHead(404, { 'Content-Type': 'application/json' });
    res.end(JSON.stringify({
      error: `Unknown endpoint: ${endpointName}`,
      available: Object.keys(endpoints)
    }));
    return;
  }

  console.log(`${req.method} /api/${endpointName} -> ${targetUrl}`);

  // Parse target URL
  const target = url.parse(targetUrl);
  const protocol = target.protocol === 'https:' ? https : http;

  // Forward request - strip all CORS-related and browser headers
  const headers = { ...req.headers };

  // Remove headers that cause LocalStack CORS issues
  delete headers.origin;
  delete headers.referer;
  delete headers['sec-fetch-site'];
  delete headers['sec-fetch-mode'];
  delete headers['sec-fetch-dest'];

  // Keep only essential headers
  const options = {
    hostname: target.hostname,
    port: target.port,
    path: target.path,
    method: req.method,
    headers: {
      'accept': headers.accept || 'application/json',
      'content-type': headers['content-type'] || 'application/json',
      'user-agent': headers['user-agent'] || 'proxy-server',
      'host': target.host
    }
  };

  const proxyReq = protocol.request(options, (proxyRes) => {
    // Filter out CORS headers from Lambda response since we set our own
    const headers = { ...proxyRes.headers };
    delete headers['access-control-allow-origin'];
    delete headers['access-control-allow-methods'];
    delete headers['access-control-allow-headers'];
    delete headers['access-control-max-age'];

    // Forward status and filtered headers
    res.writeHead(proxyRes.statusCode, headers);
    proxyRes.pipe(res);
  });

  proxyReq.on('error', (err) => {
    console.error('Proxy error:', err.message);
    res.writeHead(502, { 'Content-Type': 'application/json' });
    res.end(JSON.stringify({ error: 'Bad Gateway', message: err.message }));
  });

  req.pipe(proxyReq);
});

server.listen(PORT, () => {
  console.log('');
  console.log('==================================================');
  console.log(`Listening on: http://localhost:${PORT}`);
  console.log('==================================================');
  console.log('');
  console.log('Available endpoints:');
  for (const [name, targetUrl] of Object.entries(endpoints)) {
    console.log(`  /api/${name} -> ${targetUrl}`);
  }
  console.log('');
  console.log('==================================================');
  console.log(`Update frontend to use: http://localhost:${PORT}`);
  console.log('==================================================');
  console.log('');
});
